	}

	.arrow {
		font-size: 10px;
		transition: transform 0.2s ease;
	}

	.arrow.open {
		transform: rotate(180deg);
	}

	.dropdown-list {
		position: absolute;
		top: 100%;
		left: 0;
		right: 0;
		max-height: 200px;
		overflow-y: auto;
		background-color: rgba(30, 30, 30, 0.95);
		border: 1px solid #555;
		border-radius: 6px;
		margin-top: 2px;
		z-index: 200;
	}

	.dropdown-item {
		width: 100%;
