// FILE: packages/server/src/api/providers/list-routes.ts
import { Router } from "express";
import { promises as fs } from "fs";
import logger from "../../core/logger.js";
import { cleanListContent } from "../../core/content-processor.js";

interface ParsedEntry {
    id: string;
    label: string;
}

export interface ListProviderAdapter {
    name: string;
    filePath: string;
    parseLine(line: string): ParsedEntry | null;
    isResolved(line: string): boolean;
    resolveIdentifier(input: string): Promise<ParsedEntry | null>;
    formatEntry(entry: ParsedEntry): string;
    enrichList?(parsed: ParsedEntry[]): string[];
    resolveForRemove?(identifier: string): string;
}

export function createListRoutes(adapter: ListProviderAdapter): Router {
    const router = Router();
    const prefix = `/api/${adapter.name}`;

    router.get(prefix, async (_req, res) => {
        try {
            const content = await fs.readFile(adapter.filePath, "utf-8");
            res.type("text/plain").send(content);
        } catch (error: any) {
            if (error.code === "ENOENT") return res.type("text/plain").send("");
            logger.error(`Error reading ${adapter.name} file`, { error });
            res.status(500).send("Error reading file");
        }
    });

    router.get(`${prefix}/list`, async (_req, res) => {
        try {
            const content = await fs.readFile(adapter.filePath, "utf-8");
            const parsed = content.split("\n")
                .map(line => adapter.parseLine(line))
                .filter((p): p is ParsedEntry => p !== null);

            if (adapter.enrichList) {
                res.json(adapter.enrichList(parsed));
            } else {
                res.json(parsed.map(p => p.label));
            }
        } catch {
            res.json([]);
        }
    });

    router.post(`${prefix}/add`, async (req, res) => {
        const { identifier } = req.body;
        if (!identifier || typeof identifier !== "string") {
            return res.status(400).json({ error: "identifier required" });
        }
        try {
            const resolved = await adapter.resolveIdentifier(identifier);
            if (!resolved) {
                return res.status(404).json({ error: `Could not resolve: ${identifier}` });
            }

            let content = "";
            try { content = await fs.readFile(adapter.filePath, "utf-8"); } catch {}

            const lines = content.split("\n");
            const existingIndex = lines.findIndex(line => line.includes(resolved.id));

            if (existingIndex !== -1) {
                const existing = adapter.parseLine(lines[existingIndex]);
                if (existing?.label === resolved.label) {
                    logger.info(`${adapter.name} skip: ${resolved.id} ${resolved.label} (already exists)`);
                    return res.json({ success: true });
                }
                lines[existingIndex] = adapter.formatEntry(resolved);
                await fs.writeFile(adapter.filePath, cleanListContent(lines.join("\n")), "utf-8");
                logger.info(`${adapter.name} update: ${existing?.label} -> ${resolved.label} (id=${resolved.id})`);
                return res.json({ success: true });
            }

            const newContent = cleanListContent(content + "\n" + adapter.formatEntry(resolved));
            await fs.writeFile(adapter.filePath, newContent, "utf-8");
            logger.info(`${adapter.name} add: ${resolved.id} ${resolved.label}`);
            res.json({ success: true });
        } catch (error) {
            logger.error(`Error adding to ${adapter.name}`, { error });
            res.status(500).json({ error: "Failed to update file" });
        }
    });

    router.post(`${prefix}/remove`, async (req, res) => {
        const { identifier } = req.body;
        if (!identifier || typeof identifier !== "string") {
            return res.status(400).json({ error: "identifier required" });
        }
        try {
            const resolvedId = adapter.resolveForRemove
                ? adapter.resolveForRemove(identifier)
                : identifier;
            const content = await fs.readFile(adapter.filePath, "utf-8");
            const lines = content.split("\n").filter(line => !line.includes(resolvedId));
            await fs.writeFile(adapter.filePath, cleanListContent(lines.join("\n")), "utf-8");
            logger.info(`${adapter.name} remove: ${identifier}${resolvedId !== identifier ? ` (id: ${resolvedId})` : ""}`);
            res.json({ success: true });
        } catch (error) {
            logger.error(`Error removing from ${adapter.name} file`, { error });
            res.status(500).json({ error: "Failed to update file" });
        }
    });

    router.post(prefix, async (req, res) => {
        const { content } = req.body;
        if (typeof content !== "string") {
            return res.status(400).send("Invalid content");
        }
        try {
            const lines = content.split("\n");
            const resolved: string[] = [];

            for (const raw of lines) {
                const trimmed = raw.trim();
                if (!trimmed || trimmed.startsWith("#")) {
                    resolved.push(raw);
                    continue;
                }
                if (adapter.isResolved(trimmed)) {
                    resolved.push(raw);
                    continue;
                }
                const result = await adapter.resolveIdentifier(trimmed);
                if (!result) {
                    logger.warn(`${adapter.name} save: could not resolve "${trimmed}", skipping`);
                    continue;
                }
                const entry = adapter.formatEntry(result);
                resolved.push(entry);
                logger.info(`${adapter.name} save: resolved "${trimmed}" -> ${entry}`);
            }

            await fs.writeFile(adapter.filePath, cleanListContent(resolved.join("\n")), "utf-8");
            logger.info(`${adapter.name} file updated via web editor (smart save)`);
            res.sendStatus(200);
        } catch (error) {
            logger.error(`Error saving ${adapter.name} file`, { error });
            res.status(500).send("Error saving file");
        }
    });

    return router;
}

// FILE: packages/server/src/api/providers/sc.routes.ts
import { SC_FILE_PATH } from "../../core/config.js";
import { resolveScUsername } from "../../services/sc/apiClient.js";
import { createListRoutes, ListProviderAdapter } from "./list-routes.js";

const PREFIX = "https://stripchat.com/";

function parseUsername(identifier: string): string {
    if (identifier.includes("stripchat.com/")) {
        const parts = identifier.split("stripchat.com/");
        if (parts[1]) return parts[1].split("/")[0].split("?")[0];
    }
    return identifier;
}

const adapter: ListProviderAdapter = {
    name: "sc",
    filePath: SC_FILE_PATH,

    parseLine(line: string) {
        const trimmed = line.trim();
        if (!trimmed || trimmed.startsWith("#") || !trimmed.startsWith(PREFIX)) return null;
        const rest = trimmed.slice(PREFIX.length);
        const spaceIdx = rest.indexOf(" ");
        if (spaceIdx === -1) return { id: rest.replace(/\/$/, ""), label: rest.replace(/\/$/, "") };
        return { id: rest.slice(spaceIdx + 1), label: rest.slice(0, spaceIdx) };
    },

    isResolved(line: string) {
        const parsed = this.parseLine(line);
        return parsed !== null && parsed.id !== parsed.label;
    },

    async resolveIdentifier(input: string) {
        const username = parseUsername(input);
        const resolved = await resolveScUsername(username);
        if (!resolved) return null;
        return { id: resolved.roomId, label: resolved.username };
    },

    formatEntry(entry) {
        return `${PREFIX}${entry.label} ${entry.id}`;
    },
};

export default createListRoutes(adapter);

// FILE: packages/server/src/api/providers/tango.routes.ts
import { TANGO_FILE_PATH } from "../../core/config.js";
import { resolveAlias, fetchAliasesInBatch } from "../../services/tango/apiClient.js";
import { registry } from "../../services/aliasRefreshService.js";
import { createListRoutes, ListProviderAdapter } from "./list-routes.js";

const PREFIX = "https://tango.me/";

const adapter: ListProviderAdapter = {
    name: "tango",
    filePath: TANGO_FILE_PATH,

    parseLine(line: string) {
        const trimmed = line.trim();
        if (!trimmed || trimmed.startsWith("#") || !trimmed.startsWith(PREFIX)) return null;
        const rest = trimmed.slice(PREFIX.length);
        const spaceIdx = rest.indexOf(" ");
        if (spaceIdx === -1) return null;
        return { id: rest.slice(0, spaceIdx), label: rest.slice(spaceIdx + 1) };
    },

    isResolved(line: string) {
        return this.parseLine(line) !== null;
    },

    async resolveIdentifier(input: string) {
        const resolved = await resolveAlias(input);
        if (!resolved) return null;
        const profiles = await fetchAliasesInBatch([resolved.accountId]);
        const latestAlias = profiles?.[resolved.accountId]?.alias || input;
        return { id: resolved.accountId, label: latestAlias };
    },

    formatEntry(entry) {
        return `${PREFIX}${entry.id} ${entry.label}`;
    },

    enrichList(parsed) {
        const allAliases = registry.getAllWithHistory();
        const identifiers = new Set<string>();
        for (const { id, label } of parsed) {
            identifiers.add(id);
            identifiers.add(label);
            const cached = allAliases[id];
            if (cached) {
                for (const a of cached) identifiers.add(a);
            }
        }
        return [...identifiers];
    },

    resolveForRemove(identifier: string) {
        const reverse = registry.getReverse();
        return reverse[identifier] || identifier;
    },
};

export default createListRoutes(adapter);

