    for (let i = 0; i < lines.length; i++) {
        if (lines[i].trim().startsWith("#EXT-X-TARGETDURATION:")) {
            currentTarget = parseInt(lines[i].trim().split(":")[1], 10);
            targetLineIndex = i;
